import { useApp } from "../context/AppContext";

const NAV_ITEMS = [
{ label: "Dashboard", icon: "⊞" },
{ label: "Recipes", icon: "🍽" },
{ label: "Meal Planner", icon: "📅" },
{ label: "Shopping List", icon: "🛒" },
];

export default function Sidebar() {
const { state, dispatch } = useApp();

return (
<aside style={{ width: 220 }}> <h2>🍴 Smart Recipe</h2>


  {NAV_ITEMS.map(item => (
    <button
      key={item.label}
      onClick={() => dispatch({ type: "SET_ACTIVE_NAV", payload: item.label })}
      style={{
        display: "block",
        margin: "10px 0",
        background: state.activeNav === item.label ? "gold" : "transparent"
      }}
    >
      {item.icon} {item.label}
    </button>
  ))}

  <button onClick={() => dispatch({ type: "TOGGLE_DARK_MODE" })}>
    Toggle Theme
  </button>
</aside>


);
}
